    // BUG: Hard-deletes locally — if offline, server still has the note!
    dao.hardDelete(id)
    try {
        api.deleteNote(id)
    } catch (e: IOException) {
        // Network failed — note is gone locally but still on server!
    }
}

questions.solution:
suspend fun deleteNote(id: String) {
    val note = dao.getById(id) ?: return
    // Soft-delete: mark as DELETING so UI hides it, but row stays for sync
    dao.upsert(note.copy(syncStatus = SyncStatus.DELETING))
    syncScheduler.scheduleSync()
    // The SyncWorker will call api.deleteNote() then dao.hardDelete()
}
